    }



    // update [a, b)-th element (applied value: x)

    void update(IdxType a, IdxType b, OperatorType x) {

        update(root, a, b, x, 0, n);

    }



    // range query for [a, b)

    MonoidType query(IdxType a, IdxType b) {

        return query(root, a, b, 0, n);

